# Define a list of objects
class Person:
    def __init__(self, name, age):
        self.name = name
        self.age = age

    def __repr__(self):
        return f"Person('{self.name}', {self.age})"

people = [
    Person('John', 30),
    Person('Alice', 25),
    Person('Bob', 40)
]

# Sort the list of objects by age
try:
    people.sort(key=lambda x: x.age)
except AttributeError as e:
