# Alternatively, use the sorted function
try:
    sorted_people = sorted(people, key=lambda x: x.age)
except AttributeError as e:
    print(f"Error: {e}")

print(sorted_people)

# Sort the list in descending order
try:
    people.sort(key=lambda x: x.age, reverse=True)
except AttributeError as e:
    print(f"Error: {e}")

print(people)
